import React from "react";
import ReactSlider from "react-slider";

const Filters = ({ yearRange, setYearRange, widthRange, setWidthRange, heightRange, setHeightRange, filterData }) => {
    return (
        <aside className="filters">
            <h2>Filters</h2>
            <div className="filter-section">
                <label>Year Range:</label>
                <ReactSlider
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={yearRange}
                    onChange={value => setYearRange(value)}
                    onAfterChange={filterData}
                    min={2011}
                    max={2025}
                    pearling
                    minDistance={1}
                />
                <span>{yearRange[0]} - {yearRange[1]}</span>
            </div>
            <div className="filter-section">
                <label>Width:</label>
                <ReactSlider
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={widthRange}
                    onChange={value => setWidthRange(value)}
                    onAfterChange={filterData}
                    min={0}
                    max={100}
                    pearling
                    minDistance={1}
                />
                <span>{widthRange[0]} - {widthRange[1]}</span>
            </div>
            <div className="filter-section">
                <label>Height:</label>
                <ReactSlider
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={heightRange}
                    onChange={value => setHeightRange(value)}
                    onAfterChange={filterData}
                    min={0}
                    max={100}
                    pearling
                    minDistance={1}
                />
                <span>{heightRange[0]} - {heightRange[1]}</span>
            </div>
        </aside>
    );
};

export default Filters;
